let lineIndex = 0;const productsCache ={};function addLine(){const html = ` <div class="product-line mb-2 p-3" id="line_${lineIndex}" style="background:#f8f9fa;border-radius:8px;border-right:4px solid #667eea;"> <div class="row"> <div class="col-md-5"> <select name="lines[${lineIndex}][product_id]" class="form-control product-select" required data-index="${lineIndex}" onchange="loadProductPrice(${lineIndex})"> <option value="">ابحث عن منتج...</option> </select> </div> <div class="col-md-2"> <input type="number" name="lines[${lineIndex}][quantity]" class="form-control quantity-input" placeholder="الكمية" value="1" step="0.01" min="0.01" required onchange="calculateTotals()" onkeyup="calculateTotals()"> </div> <div class="col-md-2"> <input type="number" name="lines[${lineIndex}][unit_price]" class="form-control price-input" placeholder="السعر(AED)" step="0.01" min="0" required id="price_${lineIndex}" onchange="calculateTotals()" onkeyup="calculateTotals()" title="سعر الوحدة بالدرهم الإماراتي"> <small class="text-muted" style="font-size:0.7rem;">درهم</small> </div> <div class="col-md-2"> <input type="number" name="lines[${lineIndex}][discount_percent]" class="form-control discount-input" placeholder="خصم%" value="0" step="0.01" min="0" max="100" onchange="calculateTotals()" onkeyup="calculateTotals()"> </div> <div class="col-md-1"> <button type="button" class="btn btn-danger btn-sm" onclick="removeLine(${lineIndex})" title="حذف"> <i class="fas fa-trash"></i> </button> </div> </div> <div class="row mt-2" id="line_info_${lineIndex}" style="display:none;"> <div class="col-12"> <small class="text-muted"> <i class="fas fa-box mr-1"></i>المخزون:<span id="stock_${lineIndex}">-</span> | <i class="fas fa-dollar-sign mr-1"></i>التكلفة:<span id="cost_${lineIndex}">-</span> </small> </div> </div> </div> `;$('#linesContainer').append(html);const newSelect = $(`select[name="lines[${lineIndex}][product_id]"]`);if(window.SmartSelectors){window.SmartSelectors.initProducts(newSelect[0]);}else{newSelect.select2({ajax:{url:'/api/search',dataType:'json',delay:250,data:function(params){return{q:params.term || '',type:'products',page:params.page || 1};},processResults:function(data){return{results:(data.results || []).map(p =>({id:p.id,text:p.name || p.text,price:p.default_price || p.regular_price || p.unit_price || 0,stock:p.current_stock || 0,cost:p.cost_price || 0,unit:p.unit || 'قطعة',sku:p.sku})),pagination:{more:data.has_more || false}};}},language:'ar',dir:'rtl',placeholder:'ابحث عن منتج...',minimumInputLength:0,width:'100%'});}newSelect.on('select2:select',function(e){const selectedData = e.params.data;const currentIndex = $(this).data('index');const customerId = $('#customer_id').val();if(customerId && selectedData.id){$.ajax({url:'/sales/api/get-price',data:{product_id:selectedData.id,customer_id:customerId},success:function(data){if(data.price){$(`#price_${currentIndex}`).val(parseFloat(data.price).toFixed(2));}if(data.current_stock !== undefined){$(`#stock_${currentIndex}`).text(data.current_stock + ' ' +(data.unit || ''));$(`#line_info_${currentIndex}`).show();if(data.current_stock < 1){$(`#stock_${currentIndex}`).addClass('text-danger font-weight-bold');if(typeof azad !== 'undefined'){azad.showWarning('⚠️ تنبيه:المخزون منخفض للمنتج');}}}if(data.cost_price){$(`#cost_${currentIndex}`).text(parseFloat(data.cost_price).toFixed(2)+ ' AED');}calculateTotals();},error:function(){if(selectedData.price){$(`#price_${currentIndex}`).val(parseFloat(selectedData.price).toFixed(2));}calculateTotals();}});}else{if(selectedData.price){$(`#price_${currentIndex}`).val(parseFloat(selectedData.price).toFixed(2));}}if(selectedData.stock !== undefined){$(`#stock_${currentIndex}`).text(selectedData.stock + ' ' +(selectedData.unit || ''));$(`#line_info_${currentIndex}`).show();}if(selectedData.cost){$(`#cost_${currentIndex}`).text(parseFloat(selectedData.cost).toFixed(2)+ ' AED');}calculateTotals();});lineIndex++;$('#line_count').val(lineIndex);}function removeLine(index){$(`#line_${index}`).remove();calculateTotals();}function loadProductPrice(index){const customerId = $('#customer_id').val();const productId = $(`select[name="lines[${index}][product_id]"]`).val();if(!customerId || !productId){return;}azad.showLoading();$.ajax({url:'/sales/api/get-price',data:{product_id:productId,customer_id:customerId},success:function(data){$(`#price_${index}`).val(data.price.toFixed(2));if(data.current_stock !== undefined){$(`#stock_${index}`).text(data.current_stock + ' ' +(data.unit || ''));if(data.current_stock < 1){$(`#stock_${index}`).addClass('text-danger font-weight-bold');azad.showError(`⚠️ تنبيه:المخزون منخفض للمنتج`);}}if(data.cost_price && data.cost_price > 0){$(`#cost_${index}`).text(data.cost_price.toFixed(2)+ ' AED');}$(`#line_info_${index}`).show();calculateTotals();azad.hideLoading();},error:function(){azad.hideLoading();azad.showError('فشل تحميل السعر');}});}function calculateTotals(){let subtotal = 0;let lineCount = 0;$('[name^="lines"][name$="[quantity]"]').each(function(){const qty = parseFloat($(this).val())|| 0;const price = parseFloat($(this).closest('.product-line').find('[name$="[unit_price]"]').val())|| 0;const discount = parseFloat($(this).closest('.product-line').find('[name$="[discount_percent]"]').val())|| 0;if(qty > 0 && price > 0){const lineTotal = qty * price *(1 - discount/100);subtotal += lineTotal;lineCount++;}});const discount = parseFloat($('[name="discount_amount"]').val())|| 0;const shipping = parseFloat($('[name="shipping_cost"]').val())|| 0;const taxRate = parseFloat($('[name="tax_rate"]').val())|| 0;const afterDiscount = subtotal - discount + shipping;const tax = afterDiscount *(taxRate / 100);const total = afterDiscount + tax;$('#subtotal').text(azad.formatNumber(subtotal));$('#total').text(azad.formatNumber(total));$('#line_count_display').text(lineCount);return{subtotal:subtotal,discount:discount,shipping:shipping,tax:tax,total:total,lineCount:lineCount};}let serverExchangeRate = null;$('#currency').on('change',function(){const currency = $(this).val();const $rateInput = $('#exchange_rate');$('#payment_currency_display').text(currency);if(currency === 'AED'){$rateInput.val('1.000000');$rateInput.data('server-rate',1);serverExchangeRate = 1;$rateInput.prop('readonly',false);$rateInput.css('background-color','#e9ecef');azad.showInfo('💡 العملة:درهم - الأسعار والمدفوع بالدرهم');return;}$rateInput.val('...').css('background-color','#fff8dc');$.ajax({url:`/api/currency-rate/${currency}/AED`,success:function(data){if(data.rate){serverExchangeRate = data.rate;$rateInput.val(data.rate.toFixed(6));$rateInput.data('server-rate',data.rate);$rateInput.prop('readonly',false);$rateInput.css('background-color','#d4edda');const examplePayment = 100;const exampleAED =(examplePayment * data.rate).toFixed(2);azad.showSuccess(`✅ سعر الصرف:1 ${currency}= ${data.rate.toFixed(3)}AED\n\n💡 التوضيح:\n• الفاتورة:بالدرهم(AED)\n• المدفوع:بالـ ${currency}\n• مثال:${examplePayment}${currency}= ${exampleAED}AED`);}else if(data.manual_input_required){serverExchangeRate = null;$rateInput.val('');$rateInput.prop('readonly',false);$rateInput.css('background-color','#fff3cd');$rateInput.focus();azad.showError('⚠️ يرجى إدخال سعر الصرف يدوياً');}},error:function(){serverExchangeRate = null;$rateInput.val('');$rateInput.prop('readonly',false);$rateInput.css('background-color','#f8d7da');azad.showError('⚠️ فشل تحميل سعر الصرف - يرجى الإدخال يدوياً');}});});$('#exchange_rate').on('change',function(){const manualRate = parseFloat($(this).val());const serverRate = parseFloat($(this).data('server-rate'))|| serverExchangeRate;if(!manualRate || manualRate <= 0){azad.showError('⚠️ سعر الصرف يجب أن يكون أكبر من صفر');if(serverRate){$(this).val(serverRate.toFixed(6));}return;}if(serverRate && manualRate !== serverRate){const diff =((manualRate - serverRate)/ serverRate * 100).toFixed(2);const diffText = diff > 0 ? `+${diff}%`:`${diff}%`;if(manualRate < serverRate){$(this).css('background-color','#f8d7da');azad.showWarning(`⚠️ تحذير:سعر الصرف المدخل(${manualRate.toFixed(6)})أقل من سعر السيرفر(${serverRate.toFixed(6)})بنسبة ${diffText}` + `\nسيتم توثيق هذا التغيير في سجل العمليات`);$('#saleForm').find('input[name="exchange_rate_manual"]').remove();$('#saleForm').append(` <input type="hidden" name="exchange_rate_manual" value="true"> <input type="hidden" name="exchange_rate_server" value="${serverRate}"> <input type="hidden" name="exchange_rate_difference" value="${diff}"> `);}else if(manualRate > serverRate){$(this).css('background-color','#d1ecf1');azad.showInfo(`ℹ️ سعر الصرف المدخل أعلى من السيرفر بنسبة ${diffText}`);}else{$(this).css('background-color','#d4edda');}}else if(!serverRate){$(this).css('background-color','#fff3cd');$('#saleForm').find('input[name="exchange_rate_manual"]').remove();$('#saleForm').append(`<input type="hidden" name="exchange_rate_manual" value="true">`);}});$('#payment_method').on('change',function(){const method = $(this).val();const $container = $('#payment_fields_container');const $amountGroup = $('#payment_amount_group');$container.empty();if(!method){$amountGroup.hide();return;}$amountGroup.show();$.ajax({url:`/api/payment-fields/${method}`,success:function(data){if(data.fields && data.fields.length > 0){let html = '<hr class="my-3">';html += `<h6 class="mb-3">${data.ar_title || 'تفاصيل الدفع'}</h6>`;data.fields.forEach(field =>{const label = field.label_ar || field.label || field.name;const required = field.required ? 'required':'';const requiredStar = field.required ? ' *':'';html += ` <div class="form-group"> <label class="font-weight-bold">${label}${requiredStar}</label> `;if(field.type === 'select' && field.options){html += `<select name="${field.name}" class="form-control" ${required}>`;html += '<option value="">اختر...</option>';field.options.forEach(opt =>{html += `<option value="${opt.value}">${opt.label_ar || opt.label_en}</option>`;});html += '</select>';}else{html += ` <input type="${field.type || 'text'}" name="${field.name}" class="form-control" ${required}placeholder="${label}"> `;}html += '</div>';});$container.html(html);}},error:function(){azad.showError('⚠️ فشل تحميل حقول الدفع');}});});$(document).ready(function(){$('#customer_id').select2({placeholder:'ابحث عن زبون...',language:'ar',dir:'rtl',width:'100%',ajax:{url:'/api/search',dataType:'json',delay:250,data:function(params){return{q:params.term,type:'customers',page:params.page || 1};},processResults:function(data){return{results:data.results,pagination:{more:data.has_more}};},cache:true},minimumInputLength:0,templateResult:function(customer){if(customer.loading)return customer.text;return $('<span>' + customer.text + '</span>');},templateSelection:function(customer){return customer.text;}});addLine();$('[name="discount_amount"],[name="shipping_cost"],[name="tax_rate"]').on('change keyup',function(){calculateTotals();});$('#saleForm').on('submit',function(e){const totals = calculateTotals();if(totals.lineCount === 0){e.preventDefault();azad.showError('⚠️ يجب إضافة منتج واحد على الأقل');return false;}if(totals.total < 0){e.preventDefault();azad.showError('⚠️ الإجمالي لا يمكن أن يكون سالب');return false;}if(!$('#customer_id').val()){e.preventDefault();azad.showError('⚠️ يجب اختيار زبون');return false;}azad.showLoading();return true;});});